package github.chains;

import spoon.Launcher;
import spoon.reflect.declaration.CtImport;
import spoon.reflect.declaration.CtPackage;
import spoon.reflect.declaration.CtType;
import spoon.reflect.reference.CtTypeReference;
import spoon.reflect.visitor.filter.TypeFilter;

import java.io.File;
import java.util.List;

public class Main {
    public static void main(String[] args) {
        // Create a Spoon launcher
        Launcher launcher = new Launcher();

        // Set the source directory to process (can be parameterized)
        String sourceDirectory = "/workspace/jakartaee-mvc-sample/src/main/java";
        launcher.addInputResource(sourceDirectory);

        // Set the output directory
        String outputDirectory = "/workspace/jakartaee-mvc-sample/src/main/java";
        launcher.setSourceOutputDirectory(outputDirectory);

        // Build the model
        launcher.buildModel();

        // Get the model
        var model = launcher.getFactory().getModel();

        // Replace all javax.mvc imports with jakarta.mvc imports
        model.getElements(new TypeFilter<CtImport>(CtImport.class))
                .stream()
                .filter(importStmt -> importStmt.getReference().toString().startsWith("javax.mvc"))
                .forEach(importStmt -> {
                    String importPath = importStmt.getReference().toString();
                    String newImportPath = importPath.replace("javax.mvc", "jakarta.mvc");
                    importStmt.setReference(importStmt.getFactory().createTypeReference(newImportPath));
                });

        // Also replace any direct references in code
        model.getElements(new TypeFilter<CtTypeReference<?>>(CtTypeReference.class))
                .stream()
                .filter(typeRef -> typeRef.toString().startsWith("javax.mvc"))
                .forEach(typeRef -> {
                    String oldRef = typeRef.toString();
                    String newRef = oldRef.replace("javax.mvc", "jakarta.mvc");
                    typeRef.setSimpleName(newRef.substring(newRef.lastIndexOf('.') + 1));
                    typeRef.setPackage(typeRef.getFactory().createPackageReference(newRef.substring(0, newRef.lastIndexOf('.'))));
                });

        // Process the model to apply changes
        launcher.process();

        System.out.println("Transformation complete - all javax.mvc references updated to jakarta.mvc");
    }
}

